def solve(nums, target):
    left, right = 0, len(nums) - 1
    while left < right:
        total = nums[left] + nums[right]
        if total == target:
            return left, right
        if total < target:
            left += 1
        else:
            right -= 1
    return -1, -1

# Additional checks for pitfalls
def validate_input(nums, target):
    if not isinstance(nums, list) or not all(isinstance(x, int) for x in nums):
        raise ValueError("nums must be a list of integers")
    if not isinstance(target, int):
        raise ValueError("target must be an integer")

def solve_with_validation(nums, target):
    validate_input(nums, target)
    return solve(nums, target)
